import { Schema, model } from 'mongoose';

export const UserSchema = new Schema({
  username: { type: String, required: true, unique: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  createdAt: { type: Date, default: Date.now },
});

export const UserModel = model('User', UserSchema);

import { z } from 'zod';

export const registerUserDto = z.object({
  username: z.string().min(3),
  password: z.string().min(6),
  email: z.string().email(),
});

export type RegisterUserDto = z.infer<typeof registerUserDto>;

import { UserModel } from './user.model';
import { User } from 'types/user';

export class UserRepository {
  async createUser(user: User): Promise<User> {
    const newUser = new UserModel(user);
    return newUser.save();
  }

  async findByUsername(username: string): Promise<User | null> {
    return UserModel.findOne({ username }).exec();
  }
}

import bcrypt from 'bcryptjs';
import { UserRepository } from './user.repository';
import { RegisterUserDto } from './user.dto';
import { User } from 'types/user';

export class UserService {
  constructor(private readonly userRepository: UserRepository) {}

  async registerUser(dto: RegisterUserDto): Promise<User> {
    const passwordHash = await bcrypt.hash(dto.password, 10);
    const user: User = {
      ...dto,
      passwordHash,
      createdAt: new Date(),
    };
    return this.userRepository.createUser(user);
  }
}

import { Request, Response } from 'express';
import { AuthService } from './auth.service';
import { registerUserDto } from '../user/user.dto';

export class AuthController {
  constructor(private readonly authService: AuthService) {}

  async register(req: Request, res: Response): Promise<void> {
    const { username, password, email } = registerUserDto.parse(req.body);
    const user = await this.authService.register({ username, password, email });
    res.status(201).json({ success: true, data: user });
  }

  async login(req: Request, res: Response): Promise<void> {
    const { username, password } = req.body;
    const token = await this.authService.login({ username, password });
    res.json({ success: true, token });
  }
}

import jwt from 'jsonwebtoken';
import { UserService } from '../user/user.service';
import { RegisterUserDto } from '../user/user.dto';
import bcrypt from 'bcryptjs';
import { AppError } from '../../shared/errors/app-error';

export class AuthService {
  constructor(private readonly userService: UserService) {}

  async register(dto: RegisterUserDto) {
    return this.userService.registerUser(dto);
  }

  async login({ username, password }: { username: string; password: string }) {
    const user = await this.userService.findByUsername(username);
    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      throw new AppError('Invalid credentials', 401);
    }
    return jwt.sign({ userId: user.id }, process.env.JWT_SECRET!, { expiresIn: '1h' });
  }
}

export class AppError extends Error {
  public readonly statusCode: number;
  public readonly code: string;

  constructor(message: string, statusCode: number, code: string = 'error') {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
  }
}

import helmet from 'helmet';
import cors from 'cors';
import { Request, Response, NextFunction } from 'express';
import rateLimit from 'express-rate-limit';

export const securityMiddlewares = [
  helmet(),
  cors({ origin: process.env.ALLOWED_ORIGINS || '*' }),
  rateLimit({
    windowMs: parseInt(process.env.RATE_LIMIT_WINDOW!, 10) || 60000,
    max: parseInt(process.env.RATE_LIMIT_MAX!, 10) || 100,
  }),
];
